const product      = $('Get Product').item.json.response;
const translations = $('Webhook').item.json.body.translations;
const productUuid  = $('Webhook').item.json.body.productUuid;
const org          = $('Webhook').item.json.body.org;
const workspace    = $('Webhook').item.json.body.workspace;
const ATTR_KEY     = 'hotspot_translations';

// Keep existing attributes, upsert hotspot_translations
const attrs = (product.attributes ?? []).filter(a => a.name !== ATTR_KEY);
attrs.push({ name: ATTR_KEY, value: JSON.stringify(translations) });

// Send only the fields the platform API accepts
return [{
  json: {
    translations,
    putBody: {
      uuid:             productUuid,
      organizationSlug: org,
      clientSlug:       workspace,
      name:             product.name,
      description:      product.description ?? '',
      attributes:       attrs
    }
  }
}];
